const setup = {
  company_url: NEXUS_CODE_SETUP("company_url"),
  competitor_urls: NEXUS_CODE_SETUP("competitor_urls"),
  focus_areas: NEXUS_CODE_SETUP("focus_areas"),
  market_region: NEXUS_CODE_SETUP("market_region"),
  report_title: NEXUS_CODE_SETUP("report_title")
};

const customer = {
  company: NEXUS_CODE_CUSTOMER("company"),
  name: NEXUS_CODE_CUSTOMER("name")
};

function normalizeUrl(value) {
  const text = String(value || '').trim();
  if (!text) return '';
  if (/^https?:\/\//i.test(text)) return text;
  return 'https://' + text;
}

const companyUrl = normalizeUrl(setup.company_url);
const competitorRaw = Array.isArray(setup.competitor_urls)
  ? setup.competitor_urls.join('\n')
  : String(setup.competitor_urls || '');

const competitors = competitorRaw
  .split(/[\n,]+/)
  .map(normalizeUrl)
  .filter(Boolean)
  .slice(0, 3);

if (!companyUrl) {
  throw new Error('Missing setup.company_url. Add the buyer company website in the Nexus setup form.');
}

const focusAreas = String(setup.focus_areas || 'positioning, offers, messaging, services, pricing signals, and practical next actions').trim();
const marketRegion = String(setup.market_region || 'the buyer market').trim();
const reportTitle = String(setup.report_title || 'Monthly Competitor Website Brief').trim();

const targets = [
  {
    label: 'Buyer company',
    role: 'company',
    url: companyUrl
  },
  ...competitors.map((url, index) => ({
    label: 'Competitor ' + (index + 1),
    role: 'competitor',
    url
  }))
];

return targets.map((target, index) => ({
  json: {
    ...target,
    index,
    focus_areas: focusAreas,
    market_region: marketRegion,
    report_title: reportTitle,
    buyer_company: customer.company || '',
    buyer_name: customer.name || ''
  }
}));

const previous = $('Prepare Website Targets').item.json;
const pageTitle = String($json.page_title || previous.url || '').replace(/\s+/g, ' ').trim();
const rawText = String($json.page_text || $json.data || '').replace(/\s+/g, ' ').trim();

return [
  {
    json: {
      ...previous,
      page_title: pageTitle,
      page_text: rawText.slice(0, 12000),
      fetch_status: rawText ? 'success' : 'empty_or_failed'
    }
  }
];

const pages = $input.all().map(item => item.json);
const first = pages[0] || {};

const sections = pages.map(page => {
  return [
    'SOURCE: ' + page.label,
    'ROLE: ' + page.role,
    'URL: ' + page.url,
    'PAGE TITLE: ' + (page.page_title || 'Unknown'),
    'FETCH STATUS: ' + page.fetch_status,
    'TEXT: ' + (page.page_text || 'No readable text extracted.')
  ].join('\n');
}).join('\n\n---\n\n');

return [
  {
    json: {
      report_title: first.report_title || 'Monthly Competitor Website Brief',
      focus_areas: first.focus_areas || '',
      market_region: first.market_region || '',
      buyer_company: first.buyer_company || '',
      buyer_name: first.buyer_name || '',
      source_count: pages.length,
      pages,
      prompt_context: sections
    }
  }
];

