const promptData = $('Combine Website Text').first().json;
const aiHtml = $json.choices?.[0]?.message?.content || '';
const safeHtml = String(aiHtml || '').trim();
const title = promptData.report_title || 'Monthly Competitor Website Brief';
const summary = `Checked ${promptData.source_count || 0} website source${Number(promptData.source_count || 0) === 1 ? '' : 's'} and produced a competitor brief for ${promptData.buyer_company || 'the buyer'}.`;

return [
  {
    json: {
      output_type: 'report',
      title,
      summary,
      content_html: safeHtml || '<h1>Monthly Competitor Website Brief</h1><p>No AI report content was returned.</p>',
      content_json: {
        report_title: title,
        buyer_company: promptData.buyer_company || '',
        market_region: promptData.market_region || '',
        focus_areas: promptData.focus_areas || '',
        source_count: promptData.source_count || 0,
        sources: (promptData.pages || []).map(page => ({ label: page.label, role: page.role, url: page.url, status: page.fetch_status }))
      }
    }
  }
];
